INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  1,
  3,
  'Which summary best fits the movement of 1 Samuel 1?',
  '["Hannah pours out her grief before the LORD at Shiloh and vows that if God gives her a son she will dedicate him to lifelong service. Eli misreads her silent prayer at first, then blesses her, and the LORD opens her womb. Samuel is born, weaned, and brought to the sanctuary as a living answer to prayer.", "The Philistines defeat Israel at Mount Gilboa, and Saul''s sons fall beside him. Wounded and unable to continue, Saul falls on his own sword after his armor bearer refuses to kill him, and the Philistines later display the bodies in shame. Men of Jabesh-gilead recover the remains and bury them with fasting, ending Saul''s reign in grief and honor.", "Hannah praises the LORD for overturning the proud and lifting the humble, setting the tone for the whole book. The chapter then contrasts her faith with the corruption of Eli''s sons, who abuse sacrifices and despise the LORD''s offering. Samuel grows before God while a man of God warns Eli that his house will be judged for dishonoring the sanctuary.", "Samuel hears the LORD calling in the night, and after Eli''s help he learns to answer, \"Speak, for your servant hears.\" The message confirms judgment on Eli''s house and cannot be hidden. Samuel grows into a trustworthy prophet whose words are established throughout Israel."]'::jsonb,
  'Hannah pours out her grief before the LORD at Shiloh and vows that if God gives her a son she will dedicate him to lifelong service. Eli misreads her silent prayer at first, then blesses her, and the LORD opens her womb. Samuel is born, weaned, and brought to the sanctuary as a living answer to prayer.',
  'This summary captures the movement of 1 Samuel 1 (1 Samuel 1:1-18-1 Samuel 1:19-28).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 1
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 1?'
);

