INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  1,
  4,
  'Which summary line best expresses the narrative function of 1 Samuel 1?',
  '["Hannah pours out her grief before the LORD at Shiloh and vows that if God gives her a son she will dedicate him to lifelong service. Eli misreads her silent prayer at first, then blesses her, and the LORD opens her womb. Samuel is born, weaned, and brought to the sanctuary as a living answer to prayer.", "Hannah praises the LORD for overturning the proud and lifting the humble, setting the tone for the whole book. The chapter then contrasts her faith with the corruption of Eli''s sons, who abuse sacrifices and despise the LORD''s offering. Samuel grows before God while a man of God warns Eli that his house will be judged for dishonoring the sanctuary.", "Samuel hears the LORD calling in the night, and after Eli''s help he learns to answer, \"Speak, for your servant hears.\" The message confirms judgment on Eli''s house and cannot be hidden. Samuel grows into a trustworthy prophet whose words are established throughout Israel.", "Israel treats the ark like a talisman and marches it into battle, but the Philistines rout the army and capture the ark. Eli falls backward and dies when he hears the news, and his daughter-in-law names her son Ichabod because the glory has departed from Israel. The chapter is a stark warning that sacred objects cannot replace covenant faithfulness."]'::jsonb,
  'Hannah pours out her grief before the LORD at Shiloh and vows that if God gives her a son she will dedicate him to lifelong service. Eli misreads her silent prayer at first, then blesses her, and the LORD opens her womb. Samuel is born, weaned, and brought to the sanctuary as a living answer to prayer.',
  'This summary line expresses the narrative function of 1 Samuel 1.'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 1
    AND difficulty_stage = 4
    AND prompt = 'Which summary line best expresses the narrative function of 1 Samuel 1?'
