INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  2,
  3,
  'Which summary best fits the movement of 1 Samuel 2?',
  '["Hannah praises the LORD for overturning the proud and lifting the humble, setting the tone for the whole book. The chapter then contrasts her faith with the corruption of Eli''s sons, who abuse sacrifices and despise the LORD''s offering. Samuel grows before God while a man of God warns Eli that his house will be judged for dishonoring the sanctuary.", "Hannah pours out her grief before the LORD at Shiloh and vows that if God gives her a son she will dedicate him to lifelong service. Eli misreads her silent prayer at first, then blesses her, and the LORD opens her womb. Samuel is born, weaned, and brought to the sanctuary as a living answer to prayer.", "Samuel hears the LORD calling in the night, and after Eli''s help he learns to answer, \"Speak, for your servant hears.\" The message confirms judgment on Eli''s house and cannot be hidden. Samuel grows into a trustworthy prophet whose words are established throughout Israel.", "Israel treats the ark like a talisman and marches it into battle, but the Philistines rout the army and capture the ark. Eli falls backward and dies when he hears the news, and his daughter-in-law names her son Ichabod because the glory has departed from Israel. The chapter is a stark warning that sacred objects cannot replace covenant faithfulness."]'::jsonb,
  'Hannah praises the LORD for overturning the proud and lifting the humble, setting the tone for the whole book. The chapter then contrasts her faith with the corruption of Eli''s sons, who abuse sacrifices and despise the LORD''s offering. Samuel grows before God while a man of God warns Eli that his house will be judged for dishonoring the sanctuary.',
  'This summary captures the movement of 1 Samuel 2 (1 Samuel 2:1-10-1 Samuel 2:1-36).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 2
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 2?'
);

