  'This summary line expresses the narrative function of 1 Samuel 4.'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 4
    AND difficulty_stage = 4
    AND prompt = 'Which summary line best expresses the narrative function of 1 Samuel 4?'
);

