INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  4,
  5,
  'What final perspective best fits 1 Samuel 4?',
  '["Israel treats the ark like a talisman and marches it into battle, but the Philistines rout the army and capture the ark. Eli falls backward and dies when he hears the news, and his daughter-in-law names her son Ichabod because the glory has departed from Israel. The chapter is a stark warning that sacred objects cannot replace covenant faithfulness.", "The Philistines place the ark in Dagon''s temple, but Dagon falls before it and the people are struck with affliction. Town after town suffers because the ark brings the LORD''s presence into enemy territory. The chapter makes clear that the captured ark is not captive at all; it is still ruling.", "Saul searches for his father''s lost donkeys and is led by providence to Samuel instead. The LORD tells Samuel to anoint the man from Benjamin, and Samuel identifies Saul as the chosen one with honor at the feast. The chapter quietly introduces Saul as a tall and promising king-to-be, even before he knows it himself.", "Samuel anoints Saul, gives him signs, and tells him that the Spirit will come upon him as proof of God''s choice. Saul prophesies with the prophets, and the people marvel because the change is so unmistakable. Yet Saul also hides, hinting that his kingship will be marked by uncertainty as well as promise."]'::jsonb,
  'Israel treats the ark like a talisman and marches it into battle, but the Philistines rout the army and capture the ark. Eli falls backward and dies when he hears the news, and his daughter-in-law names her son Ichabod because the glory has departed from Israel. The chapter is a stark warning that sacred objects cannot replace covenant faithfulness.',
  'This final perspective fits 1 Samuel 4 (1 Samuel 4:1-11-1 Samuel 4:1-11).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 4
    AND difficulty_stage = 5
    AND prompt = 'What final perspective best fits 1 Samuel 4?'
);

