INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  5,
  4,
  'Which summary line best expresses the narrative function of 1 Samuel 5?',
  '["The Philistines place the ark in Dagon''s temple, but Dagon falls before it and the people are struck with affliction. Town after town suffers because the ark brings the LORD''s presence into enemy territory. The chapter makes clear that the captured ark is not captive at all; it is still ruling.", "The Philistines send the ark back on a new cart with guilt offerings, testing whether the plague came from God or chance. The cows head straight for Beth-shemesh, confirming that the LORD is guiding the return. Israel rejoices but also learns reverence when some men look into the ark and are struck down.", "Samuel calls Israel to put away foreign gods and gather at Mizpah in repentance and prayer. As the Philistines come up against them, Samuel cries to the LORD, and God thunders on the enemy while Israel pursues the victory. The chapter ends with Samuel judging Israel and setting up memorials to the LORD''s help.", "When Samuel grows old and his sons do not walk in his ways, Israel asks for a king like the nations around them. Samuel is grieved, but the LORD tells him that the request is really a rejection of God''s own rule. Samuel warns them about royal cost and burden, yet the people persist and the monarchy becomes the answer to their demand."]'::jsonb,
  'The Philistines place the ark in Dagon''s temple, but Dagon falls before it and the people are struck with affliction. Town after town suffers because the ark brings the LORD''s presence into enemy territory. The chapter makes clear that the captured ark is not captive at all; it is still ruling.',
  'This summary line expresses the narrative function of 1 Samuel 5.'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 5
    AND difficulty_stage = 4
    AND prompt = 'Which summary line best expresses the narrative function of 1 Samuel 5?'
);

