INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  8,
  3,
  'Which summary best fits the movement of 1 Samuel 8?',
  '["When Samuel grows old and his sons do not walk in his ways, Israel asks for a king like the nations around them. Samuel is grieved, but the LORD tells him that the request is really a rejection of God''s own rule. Samuel warns them about royal cost and burden, yet the people persist and the monarchy becomes the answer to their demand.", "Samuel calls Israel to put away foreign gods and gather at Mizpah in repentance and prayer. As the Philistines come up against them, Samuel cries to the LORD, and God thunders on the enemy while Israel pursues the victory. The chapter ends with Samuel judging Israel and setting up memorials to the LORD''s help.", "Saul searches for his father''s lost donkeys and is led by providence to Samuel instead. The LORD tells Samuel to anoint the man from Benjamin, and Samuel identifies Saul as the chosen one with honor at the feast. The chapter quietly introduces Saul as a tall and promising king-to-be, even before he knows it himself.", "Samuel anoints Saul, gives him signs, and tells him that the Spirit will come upon him as proof of God''s choice. Saul prophesies with the prophets, and the people marvel because the change is so unmistakable. Yet Saul also hides, hinting that his kingship will be marked by uncertainty as well as promise."]'::jsonb,
  'When Samuel grows old and his sons do not walk in his ways, Israel asks for a king like the nations around them. Samuel is grieved, but the LORD tells him that the request is really a rejection of God''s own rule. Samuel warns them about royal cost and burden, yet the people persist and the monarchy becomes the answer to their demand.',
  'This summary captures the movement of 1 Samuel 8 (1 Samuel 8:1-9-1 Samuel 8:1-9).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 8
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 8?'
);

