INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  9,
  3,
  'Which summary best fits the movement of 1 Samuel 9?',
  '["Saul searches for his father''s lost donkeys and is led by providence to Samuel instead. The LORD tells Samuel to anoint the man from Benjamin, and Samuel identifies Saul as the chosen one with honor at the feast. The chapter quietly introduces Saul as a tall and promising king-to-be, even before he knows it himself.", "When Samuel grows old and his sons do not walk in his ways, Israel asks for a king like the nations around them. Samuel is grieved, but the LORD tells him that the request is really a rejection of God''s own rule. Samuel warns them about royal cost and burden, yet the people persist and the monarchy becomes the answer to their demand.", "Samuel anoints Saul, gives him signs, and tells him that the Spirit will come upon him as proof of God''s choice. Saul prophesies with the prophets, and the people marvel because the change is so unmistakable. Yet Saul also hides, hinting that his kingship will be marked by uncertainty as well as promise.", "When Nahash the Ammonite threatens Jabesh-gilead, Saul is moved by the Spirit and gathers Israel to rescue the city. The victory unites the tribes and confirms Saul''s public kingship at Gilgal. The chapter shows the best side of Saul: courage, mercy, and the ability to rally a divided people."]'::jsonb,
  'Saul searches for his father''s lost donkeys and is led by providence to Samuel instead. The LORD tells Samuel to anoint the man from Benjamin, and Samuel identifies Saul as the chosen one with honor at the feast. The chapter quietly introduces Saul as a tall and promising king-to-be, even before he knows it himself.',
  'This summary captures the movement of 1 Samuel 9 (1 Samuel 9:1-10-1 Samuel 9:1-14).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 9
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 9?'
);

