INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  11,
  3,
  'Which summary best fits the movement of 1 Samuel 11?',
  '["When Nahash the Ammonite threatens Jabesh-gilead, Saul is moved by the Spirit and gathers Israel to rescue the city. The victory unites the tribes and confirms Saul''s public kingship at Gilgal. The chapter shows the best side of Saul: courage, mercy, and the ability to rally a divided people.", "Samuel anoints Saul, gives him signs, and tells him that the Spirit will come upon him as proof of God''s choice. Saul prophesies with the prophets, and the people marvel because the change is so unmistakable. Yet Saul also hides, hinting that his kingship will be marked by uncertainty as well as promise.", "Samuel reviews his leadership, insists that he has taken no bribe, and reminds Israel how the LORD repeatedly rescued them from enemies. He warns that asking for a king does not remove accountability, and he calls both ruler and people to fear and serve the LORD. The speech closes the era of judges with a moral and spiritual summary.", "Saul grows anxious when the Philistines mass and Samuel does not arrive on time, so he offers the burnt offering himself. Samuel rebukes him for acting foolishly and announces that his kingdom will not endure. The chapter marks the first clear break between Saul''s kingship and God''s enduring purpose."]'::jsonb,
  'When Nahash the Ammonite threatens Jabesh-gilead, Saul is moved by the Spirit and gathers Israel to rescue the city. The victory unites the tribes and confirms Saul''s public kingship at Gilgal. The chapter shows the best side of Saul: courage, mercy, and the ability to rally a divided people.',
  'This summary captures the movement of 1 Samuel 11 (1 Samuel 11:1-11-1 Samuel 11:8-15).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 11
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 11?'
);

