INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  12,
  3,
  'Which summary best fits the movement of 1 Samuel 12?',
  '["Samuel reviews his leadership, insists that he has taken no bribe, and reminds Israel how the LORD repeatedly rescued them from enemies. He warns that asking for a king does not remove accountability, and he calls both ruler and people to fear and serve the LORD. The speech closes the era of judges with a moral and spiritual summary.", "When Nahash the Ammonite threatens Jabesh-gilead, Saul is moved by the Spirit and gathers Israel to rescue the city. The victory unites the tribes and confirms Saul''s public kingship at Gilgal. The chapter shows the best side of Saul: courage, mercy, and the ability to rally a divided people.", "Saul grows anxious when the Philistines mass and Samuel does not arrive on time, so he offers the burnt offering himself. Samuel rebukes him for acting foolishly and announces that his kingdom will not endure. The chapter marks the first clear break between Saul''s kingship and God''s enduring purpose.", "Jonathan and his armor bearer trust the LORD and spark a panic among the Philistines, showing that faith can win where armies hesitate. Saul''s rash oath, however, weakens the people and nearly costs Jonathan his life after the king''s own son tastes honey. The chapter contrasts brave initiative with foolish religion and ends with Saul''s damaged leadership."]'::jsonb,
  'Samuel reviews his leadership, insists that he has taken no bribe, and reminds Israel how the LORD repeatedly rescued them from enemies. He warns that asking for a king does not remove accountability, and he calls both ruler and people to fear and serve the LORD. The speech closes the era of judges with a moral and spiritual summary.',
  'This summary captures the movement of 1 Samuel 12 (1 Samuel 12:1-5-1 Samuel 12:1-15).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 12
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 12?'
);

