INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  12,
  4,
  'Which summary line best expresses the narrative function of 1 Samuel 12?',
  '["Samuel reviews his leadership, insists that he has taken no bribe, and reminds Israel how the LORD repeatedly rescued them from enemies. He warns that asking for a king does not remove accountability, and he calls both ruler and people to fear and serve the LORD. The speech closes the era of judges with a moral and spiritual summary.", "Saul grows anxious when the Philistines mass and Samuel does not arrive on time, so he offers the burnt offering himself. Samuel rebukes him for acting foolishly and announces that his kingdom will not endure. The chapter marks the first clear break between Saul''s kingship and God''s enduring purpose.", "Jonathan and his armor bearer trust the LORD and spark a panic among the Philistines, showing that faith can win where armies hesitate. Saul''s rash oath, however, weakens the people and nearly costs Jonathan his life after the king''s own son tastes honey. The chapter contrasts brave initiative with foolish religion and ends with Saul''s damaged leadership.", "Samuel commands Saul to destroy Amalek completely, but Saul spares the best livestock and keeps King Agag alive. When confronted, Saul blames the people, but Samuel declares that obedience is better than sacrifice and that the LORD has rejected Saul as king. The chapter ends with Agag''s death and Samuel''s grief over Saul''s failure."]'::jsonb,
  'Samuel reviews his leadership, insists that he has taken no bribe, and reminds Israel how the LORD repeatedly rescued them from enemies. He warns that asking for a king does not remove accountability, and he calls both ruler and people to fear and serve the LORD. The speech closes the era of judges with a moral and spiritual summary.',
  'This summary line expresses the narrative function of 1 Samuel 12.'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 12
    AND difficulty_stage = 4
    AND prompt = 'Which summary line best expresses the narrative function of 1 Samuel 12?'
);

