INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  12,
  5,
  'What final perspective best fits 1 Samuel 12?',
  '["Samuel reviews his leadership, insists that he has taken no bribe, and reminds Israel how the LORD repeatedly rescued them from enemies. He warns that asking for a king does not remove accountability, and he calls both ruler and people to fear and serve the LORD. The speech closes the era of judges with a moral and spiritual summary.", "Saul grows anxious when the Philistines mass and Samuel does not arrive on time, so he offers the burnt offering himself. Samuel rebukes him for acting foolishly and announces that his kingdom will not endure. The chapter marks the first clear break between Saul''s kingship and God''s enduring purpose.", "David comes to the battlefield with bread for his brothers and ends up facing Goliath, the giant who mocks the armies of the living God. David declares that the battle belongs to the LORD, strikes Goliath with a sling stone, and wins a decisive victory with the giant''s own sword. The chapter celebrates faith that sees God''s honor where others see only impossible odds.", "Jonathan loves David as his own soul, and the two men form a covenant that lasts beyond politics. David succeeds in everything he does, which makes Saul jealous and afraid as the people''s praise shifts toward the young warrior. The chapter moves from friendship to rising royal tension."]'::jsonb,
  'Samuel reviews his leadership, insists that he has taken no bribe, and reminds Israel how the LORD repeatedly rescued them from enemies. He warns that asking for a king does not remove accountability, and he calls both ruler and people to fear and serve the LORD. The speech closes the era of judges with a moral and spiritual summary.',
  'This final perspective fits 1 Samuel 12 (1 Samuel 12:1-5-1 Samuel 12:1-15).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 12
    AND difficulty_stage = 5
    AND prompt = 'What final perspective best fits 1 Samuel 12?'
);

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  12,
