INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  14,
  3,
  'Which summary best fits the movement of 1 Samuel 14?',
  '["Jonathan and his armor bearer trust the LORD and spark a panic among the Philistines, showing that faith can win where armies hesitate. Saul''s rash oath, however, weakens the people and nearly costs Jonathan his life after the king''s own son tastes honey. The chapter contrasts brave initiative with foolish religion and ends with Saul''s damaged leadership.", "Saul grows anxious when the Philistines mass and Samuel does not arrive on time, so he offers the burnt offering himself. Samuel rebukes him for acting foolishly and announces that his kingdom will not endure. The chapter marks the first clear break between Saul''s kingship and God''s enduring purpose.", "Samuel commands Saul to destroy Amalek completely, but Saul spares the best livestock and keeps King Agag alive. When confronted, Saul blames the people, but Samuel declares that obedience is better than sacrifice and that the LORD has rejected Saul as king. The chapter ends with Agag''s death and Samuel''s grief over Saul''s failure.", "The LORD sends Samuel to Bethlehem to anoint a new king from Jesse''s sons, and David is chosen because the LORD looks on the heart. The Spirit comes upon David, while an evil spirit troubles Saul and leads to the introduction of David as a musician in the court. The chapter quietly begins the rise of Israel''s future king."]'::jsonb,
  'Jonathan and his armor bearer trust the LORD and spark a panic among the Philistines, showing that faith can win where armies hesitate. Saul''s rash oath, however, weakens the people and nearly costs Jonathan his life after the king''s own son tastes honey. The chapter contrasts brave initiative with foolish religion and ends with Saul''s damaged leadership.',
  'This summary captures the movement of 1 Samuel 14 (1 Samuel 14:1-15-1 Samuel 14:1-52).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 14
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 14?'
);

