INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  14,
  4,
  'Which summary line best expresses the narrative function of 1 Samuel 14?',
  '["Jonathan and his armor bearer trust the LORD and spark a panic among the Philistines, showing that faith can win where armies hesitate. Saul''s rash oath, however, weakens the people and nearly costs Jonathan his life after the king''s own son tastes honey. The chapter contrasts brave initiative with foolish religion and ends with Saul''s damaged leadership.", "Samuel commands Saul to destroy Amalek completely, but Saul spares the best livestock and keeps King Agag alive. When confronted, Saul blames the people, but Samuel declares that obedience is better than sacrifice and that the LORD has rejected Saul as king. The chapter ends with Agag''s death and Samuel''s grief over Saul''s failure.", "The LORD sends Samuel to Bethlehem to anoint a new king from Jesse''s sons, and David is chosen because the LORD looks on the heart. The Spirit comes upon David, while an evil spirit troubles Saul and leads to the introduction of David as a musician in the court. The chapter quietly begins the rise of Israel''s future king.", "David comes to the battlefield with bread for his brothers and ends up facing Goliath, the giant who mocks the armies of the living God. David declares that the battle belongs to the LORD, strikes Goliath with a sling stone, and wins a decisive victory with the giant''s own sword. The chapter celebrates faith that sees God''s honor where others see only impossible odds."]'::jsonb,
  'Jonathan and his armor bearer trust the LORD and spark a panic among the Philistines, showing that faith can win where armies hesitate. Saul''s rash oath, however, weakens the people and nearly costs Jonathan his life after the king''s own son tastes honey. The chapter contrasts brave initiative with foolish religion and ends with Saul''s damaged leadership.',
  'This summary line expresses the narrative function of 1 Samuel 14.'
WHERE NOT EXISTS (
