INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  15,
  3,
  'Which summary best fits the movement of 1 Samuel 15?',
  '["Samuel commands Saul to destroy Amalek completely, but Saul spares the best livestock and keeps King Agag alive. When confronted, Saul blames the people, but Samuel declares that obedience is better than sacrifice and that the LORD has rejected Saul as king. The chapter ends with Agag''s death and Samuel''s grief over Saul''s failure.", "Jonathan and his armor bearer trust the LORD and spark a panic among the Philistines, showing that faith can win where armies hesitate. Saul''s rash oath, however, weakens the people and nearly costs Jonathan his life after the king''s own son tastes honey. The chapter contrasts brave initiative with foolish religion and ends with Saul''s damaged leadership.", "The LORD sends Samuel to Bethlehem to anoint a new king from Jesse''s sons, and David is chosen because the LORD looks on the heart. The Spirit comes upon David, while an evil spirit troubles Saul and leads to the introduction of David as a musician in the court. The chapter quietly begins the rise of Israel''s future king.", "David comes to the battlefield with bread for his brothers and ends up facing Goliath, the giant who mocks the armies of the living God. David declares that the battle belongs to the LORD, strikes Goliath with a sling stone, and wins a decisive victory with the giant''s own sword. The chapter celebrates faith that sees God''s honor where others see only impossible odds."]'::jsonb,
  'Samuel commands Saul to destroy Amalek completely, but Saul spares the best livestock and keeps King Agag alive. When confronted, Saul blames the people, but Samuel declares that obedience is better than sacrifice and that the LORD has rejected Saul as king. The chapter ends with Agag''s death and Samuel''s grief over Saul''s failure.',
  'This summary captures the movement of 1 Samuel 15 (1 Samuel 15:1-9-1 Samuel 15:1-23).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 15
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 15?'
);

