INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  20,
  5,
  'What final perspective best fits 1 Samuel 20?',
  '["David and Jonathan use a secret sign at the feast to determine Saul''s intent, and Saul''s murderous anger is confirmed. The two friends renew their covenant and part with grief, knowing the kingdom''s conflict will separate them. The chapter deepens the tragedy by showing loyalty trapped inside royal violence.", "David arrives at Nob hungry and receives the holy bread and Goliath''s sword from Ahimelech, but the encounter later costs the priests their lives. He then flees to Gath, where he pretends madness to survive among the Philistines. The chapter shows David in exile, scrambling for food, weapons, and safety while Saul''s violence expands.", "Samuel dies, and David moves deeper into the wilderness where Nabal insults him and refuses food for his men. Abigail quickly intervenes with provisions, speaks humbly to David, and prevents bloodshed by reminding him that the LORD will fight his battles. Nabal later dies after his drunken feast, and David receives Abigail as wife, turning restraint into mercy and provision into peace.", "When Saul camps in the wilderness, David slips into the camp with Abishai and takes Saul''s spear and water jug instead of killing him. From a distance he calls Saul to account, and Saul again admits that he has sinned and that David will surely prevail. The second chance underlines David''s refusal to seize the throne by violence."]'::jsonb,
  'David and Jonathan use a secret sign at the feast to determine Saul''s intent, and Saul''s murderous anger is confirmed. The two friends renew their covenant and part with grief, knowing the kingdom''s conflict will separate them. The chapter deepens the tragedy by showing loyalty trapped inside royal violence.',
  'This final perspective fits 1 Samuel 20 (1 Samuel 20:1-23-1 Samuel 20:1-23).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 20
    AND difficulty_stage = 5
    AND prompt = 'What final perspective best fits 1 Samuel 20?'
);

