INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  23,
  3,
  'Which summary best fits the movement of 1 Samuel 23?',
  '["David rescues Keilah from the Philistines and then discovers that the city may still betray him to Saul. He repeatedly seeks the LORD, who directs him away from capture and into the wilderness, where the Ziphites inform Saul of his location. The chapter shows David relying on God''s guidance in every movement.", "David gathers a band of distressed followers in the cave of Adullam while Saul''s suspicion turns into murderous paranoia. Doeg tells Saul that Ahimelech helped David, and the king orders the priests of Nob killed, deepening the bloodguilt on his house. Abiathar escapes to David, linking the outlaw king and the surviving priesthood.", "David has the chance to kill Saul in the cave at En-gedi but chooses instead to cut off a corner of Saul''s robe and let God judge between them. Saul is briefly softened and acknowledges David''s future kingship, yet the conflict is not truly resolved. The chapter shows David''s restraint and trust in the LORD rather than revenge.", "Samuel dies, and David moves deeper into the wilderness where Nabal insults him and refuses food for his men. Abigail quickly intervenes with provisions, speaks humbly to David, and prevents bloodshed by reminding him that the LORD will fight his battles. Nabal later dies after his drunken feast, and David receives Abigail as wife, turning restraint into mercy and provision into peace."]'::jsonb,
  'David rescues Keilah from the Philistines and then discovers that the city may still betray him to Saul. He repeatedly seeks the LORD, who directs him away from capture and into the wilderness, where the Ziphites inform Saul of his location. The chapter shows David relying on God''s guidance in every movement.',
  'This summary captures the movement of 1 Samuel 23 (1 Samuel 23:1-14-1 Samuel 23:15-29).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 23
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 23?'
);

