INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  24,
  3,
  'Which summary best fits the movement of 1 Samuel 24?',
  '["David has the chance to kill Saul in the cave at En-gedi but chooses instead to cut off a corner of Saul''s robe and let God judge between them. Saul is briefly softened and acknowledges David''s future kingship, yet the conflict is not truly resolved. The chapter shows David''s restraint and trust in the LORD rather than revenge.", "David rescues Keilah from the Philistines and then discovers that the city may still betray him to Saul. He repeatedly seeks the LORD, who directs him away from capture and into the wilderness, where the Ziphites inform Saul of his location. The chapter shows David relying on God''s guidance in every movement.", "Samuel dies, and David moves deeper into the wilderness where Nabal insults him and refuses food for his men. Abigail quickly intervenes with provisions, speaks humbly to David, and prevents bloodshed by reminding him that the LORD will fight his battles. Nabal later dies after his drunken feast, and David receives Abigail as wife, turning restraint into mercy and provision into peace.", "When Saul camps in the wilderness, David slips into the camp with Abishai and takes Saul''s spear and water jug instead of killing him. From a distance he calls Saul to account, and Saul again admits that he has sinned and that David will surely prevail. The second chance underlines David''s refusal to seize the throne by violence."]'::jsonb,
  'David has the chance to kill Saul in the cave at En-gedi but chooses instead to cut off a corner of Saul''s robe and let God judge between them. Saul is briefly softened and acknowledges David''s future kingship, yet the conflict is not truly resolved. The chapter shows David''s restraint and trust in the LORD rather than revenge.',
  'This summary captures the movement of 1 Samuel 24 (1 Samuel 24:1-7-1 Samuel 24:1-15).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 24
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 24?'
);

