INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  24,
  4,
  'Which summary line best expresses the narrative function of 1 Samuel 24?',
  '["David has the chance to kill Saul in the cave at En-gedi but chooses instead to cut off a corner of Saul''s robe and let God judge between them. Saul is briefly softened and acknowledges David''s future kingship, yet the conflict is not truly resolved. The chapter shows David''s restraint and trust in the LORD rather than revenge.", "Samuel dies, and David moves deeper into the wilderness where Nabal insults him and refuses food for his men. Abigail quickly intervenes with provisions, speaks humbly to David, and prevents bloodshed by reminding him that the LORD will fight his battles. Nabal later dies after his drunken feast, and David receives Abigail as wife, turning restraint into mercy and provision into peace.", "When Saul camps in the wilderness, David slips into the camp with Abishai and takes Saul''s spear and water jug instead of killing him. From a distance he calls Saul to account, and Saul again admits that he has sinned and that David will surely prevail. The second chance underlines David''s refusal to seize the throne by violence.", "David decides he will perish by Saul''s hand unless he finds refuge among the Philistines, so he settles in Ziklag under Achish. From there he raids surrounding peoples while telling Achish that he has struck Judah, keeping the king of Gath confident in his loyalty. The chapter captures David living by concealment and survival in enemy territory."]'::jsonb,
  'David has the chance to kill Saul in the cave at En-gedi but chooses instead to cut off a corner of Saul''s robe and let God judge between them. Saul is briefly softened and acknowledges David''s future kingship, yet the conflict is not truly resolved. The chapter shows David''s restraint and trust in the LORD rather than revenge.',
  'This summary line expresses the narrative function of 1 Samuel 24.'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 24
    AND difficulty_stage = 4
    AND prompt = 'Which summary line best expresses the narrative function of 1 Samuel 24?'
);

