INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  24,
  5,
  'What final perspective best fits 1 Samuel 24?',
  '["David has the chance to kill Saul in the cave at En-gedi but chooses instead to cut off a corner of Saul''s robe and let God judge between them. Saul is briefly softened and acknowledges David''s future kingship, yet the conflict is not truly resolved. The chapter shows David''s restraint and trust in the LORD rather than revenge.", "Samuel dies, and David moves deeper into the wilderness where Nabal insults him and refuses food for his men. Abigail quickly intervenes with provisions, speaks humbly to David, and prevents bloodshed by reminding him that the LORD will fight his battles. Nabal later dies after his drunken feast, and David receives Abigail as wife, turning restraint into mercy and provision into peace.", "As the Philistines assemble for war, their lords distrust David and insist that he not march with them. Achish defends David''s loyalty, but the commanders fear he will turn against them in battle, so David is sent home from Aphek. The chapter frees David from an impossible battlefield alliance before the final crisis with Saul unfolds.", "While David and his men are away, Amalekites raid Ziklag, burn the city, and take the families captive. David strengthens himself in the LORD, pursues the raiders with divine guidance, and recovers everyone along with much spoil. The chapter ends with David sharing the recovered goods widely, showing both courage and generosity."]'::jsonb,
  'David has the chance to kill Saul in the cave at En-gedi but chooses instead to cut off a corner of Saul''s robe and let God judge between them. Saul is briefly softened and acknowledges David''s future kingship, yet the conflict is not truly resolved. The chapter shows David''s restraint and trust in the LORD rather than revenge.',
  'This final perspective fits 1 Samuel 24 (1 Samuel 24:1-7-1 Samuel 24:1-15).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 24
    AND difficulty_stage = 5
    AND prompt = 'What final perspective best fits 1 Samuel 24?'
);

