INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  26,
  3,
  'Which summary best fits the movement of 1 Samuel 26?',
  '["When Saul camps in the wilderness, David slips into the camp with Abishai and takes Saul''s spear and water jug instead of killing him. From a distance he calls Saul to account, and Saul again admits that he has sinned and that David will surely prevail. The second chance underlines David''s refusal to seize the throne by violence.", "Samuel dies, and David moves deeper into the wilderness where Nabal insults him and refuses food for his men. Abigail quickly intervenes with provisions, speaks humbly to David, and prevents bloodshed by reminding him that the LORD will fight his battles. Nabal later dies after his drunken feast, and David receives Abigail as wife, turning restraint into mercy and provision into peace.", "David decides he will perish by Saul''s hand unless he finds refuge among the Philistines, so he settles in Ziklag under Achish. From there he raids surrounding peoples while telling Achish that he has struck Judah, keeping the king of Gath confident in his loyalty. The chapter captures David living by concealment and survival in enemy territory.", "Saul becomes desperate when the Philistines gather and the LORD no longer answers him, so he disguises himself and seeks a medium at Endor. The woman summons Samuel, who rebukes Saul and repeats that the LORD has torn the kingdom away from him. Saul hears the sentence of death before returning to face the battle."]'::jsonb,
  'When Saul camps in the wilderness, David slips into the camp with Abishai and takes Saul''s spear and water jug instead of killing him. From a distance he calls Saul to account, and Saul again admits that he has sinned and that David will surely prevail. The second chance underlines David''s refusal to seize the throne by violence.',
  'This summary captures the movement of 1 Samuel 26 (1 Samuel 26:1-12-1 Samuel 26:13-25).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 26
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 26?'
);

