INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  27,
  3,
  'Which summary best fits the movement of 1 Samuel 27?',
  '["David decides he will perish by Saul''s hand unless he finds refuge among the Philistines, so he settles in Ziklag under Achish. From there he raids surrounding peoples while telling Achish that he has struck Judah, keeping the king of Gath confident in his loyalty. The chapter captures David living by concealment and survival in enemy territory.", "When Saul camps in the wilderness, David slips into the camp with Abishai and takes Saul''s spear and water jug instead of killing him. From a distance he calls Saul to account, and Saul again admits that he has sinned and that David will surely prevail. The second chance underlines David''s refusal to seize the throne by violence.", "Saul becomes desperate when the Philistines gather and the LORD no longer answers him, so he disguises himself and seeks a medium at Endor. The woman summons Samuel, who rebukes Saul and repeats that the LORD has torn the kingdom away from him. Saul hears the sentence of death before returning to face the battle.", "As the Philistines assemble for war, their lords distrust David and insist that he not march with them. Achish defends David''s loyalty, but the commanders fear he will turn against them in battle, so David is sent home from Aphek. The chapter frees David from an impossible battlefield alliance before the final crisis with Saul unfolds."]'::jsonb,
  'David decides he will perish by Saul''s hand unless he finds refuge among the Philistines, so he settles in Ziklag under Achish. From there he raids surrounding peoples while telling Achish that he has struck Judah, keeping the king of Gath confident in his loyalty. The chapter captures David living by concealment and survival in enemy territory.',
  'This summary captures the movement of 1 Samuel 27 (1 Samuel 27:1-7-1 Samuel 27:1-7).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 27
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 27?'
);

