INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  28,
  3,
  'Which summary best fits the movement of 1 Samuel 28?',
  '["Saul becomes desperate when the Philistines gather and the LORD no longer answers him, so he disguises himself and seeks a medium at Endor. The woman summons Samuel, who rebukes Saul and repeats that the LORD has torn the kingdom away from him. Saul hears the sentence of death before returning to face the battle.", "David decides he will perish by Saul''s hand unless he finds refuge among the Philistines, so he settles in Ziklag under Achish. From there he raids surrounding peoples while telling Achish that he has struck Judah, keeping the king of Gath confident in his loyalty. The chapter captures David living by concealment and survival in enemy territory.", "As the Philistines assemble for war, their lords distrust David and insist that he not march with them. Achish defends David''s loyalty, but the commanders fear he will turn against them in battle, so David is sent home from Aphek. The chapter frees David from an impossible battlefield alliance before the final crisis with Saul unfolds.", "While David and his men are away, Amalekites raid Ziklag, burn the city, and take the families captive. David strengthens himself in the LORD, pursues the raiders with divine guidance, and recovers everyone along with much spoil. The chapter ends with David sharing the recovered goods widely, showing both courage and generosity."]'::jsonb,
  'Saul becomes desperate when the Philistines gather and the LORD no longer answers him, so he disguises himself and seeks a medium at Endor. The woman summons Samuel, who rebukes Saul and repeats that the LORD has torn the kingdom away from him. Saul hears the sentence of death before returning to face the battle.',
  'This summary captures the movement of 1 Samuel 28 (1 Samuel 28:1-7-1 Samuel 28:1-25).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 28
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 1 Samuel 28?'
);

