INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  29,
  5,
  'What final perspective best fits 1 Samuel 29?',
  '["As the Philistines assemble for war, their lords distrust David and insist that he not march with them. Achish defends David''s loyalty, but the commanders fear he will turn against them in battle, so David is sent home from Aphek. The chapter frees David from an impossible battlefield alliance before the final crisis with Saul unfolds.", "While David and his men are away, Amalekites raid Ziklag, burn the city, and take the families captive. David strengthens himself in the LORD, pursues the raiders with divine guidance, and recovers everyone along with much spoil. The chapter ends with David sharing the recovered goods widely, showing both courage and generosity.", "Samuel hears the LORD calling in the night, and after Eli''s help he learns to answer, \"Speak, for your servant hears.\" The message confirms judgment on Eli''s house and cannot be hidden. Samuel grows into a trustworthy prophet whose words are established throughout Israel.", "Israel treats the ark like a talisman and marches it into battle, but the Philistines rout the army and capture the ark. Eli falls backward and dies when he hears the news, and his daughter-in-law names her son Ichabod because the glory has departed from Israel. The chapter is a stark warning that sacred objects cannot replace covenant faithfulness."]'::jsonb,
  'As the Philistines assemble for war, their lords distrust David and insist that he not march with them. Achish defends David''s loyalty, but the commanders fear he will turn against them in battle, so David is sent home from Aphek. The chapter frees David from an impossible battlefield alliance before the final crisis with Saul unfolds.',
  'This final perspective fits 1 Samuel 29 (1 Samuel 29:1-3-1 Samuel 29:1-11).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 29
    AND difficulty_stage = 5
    AND prompt = 'What final perspective best fits 1 Samuel 29?'
);

