INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  30,
  5,
  'What final perspective best fits 1 Samuel 30?',
  '["While David and his men are away, Amalekites raid Ziklag, burn the city, and take the families captive. David strengthens himself in the LORD, pursues the raiders with divine guidance, and recovers everyone along with much spoil. The chapter ends with David sharing the recovered goods widely, showing both courage and generosity.", "The Philistines defeat Israel at Mount Gilboa, and Saul''s sons fall beside him. Wounded and unable to continue, Saul falls on his own sword after his armor bearer refuses to kill him, and the Philistines later display the bodies in shame. Men of Jabesh-gilead recover the remains and bury them with fasting, ending Saul''s reign in grief and honor.", "Israel treats the ark like a talisman and marches it into battle, but the Philistines rout the army and capture the ark. Eli falls backward and dies when he hears the news, and his daughter-in-law names her son Ichabod because the glory has departed from Israel. The chapter is a stark warning that sacred objects cannot replace covenant faithfulness.", "The Philistines place the ark in Dagon''s temple, but Dagon falls before it and the people are struck with affliction. Town after town suffers because the ark brings the LORD''s presence into enemy territory. The chapter makes clear that the captured ark is not captive at all; it is still ruling."]'::jsonb,
  'While David and his men are away, Amalekites raid Ziklag, burn the city, and take the families captive. David strengthens himself in the LORD, pursues the raiders with divine guidance, and recovers everyone along with much spoil. The chapter ends with David sharing the recovered goods widely, showing both courage and generosity.',
  'This final perspective fits 1 Samuel 30 (1 Samuel 30:1-8-1 Samuel 30:1-31).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 30
    AND difficulty_stage = 5
    AND prompt = 'What final perspective best fits 1 Samuel 30?'
);

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  30,
  5,
  'Which advanced summary best matches 1 Samuel 30?',
  '["While David and his men are away, Amalekites raid Ziklag, burn the city, and take the families captive. David strengthens himself in the LORD, pursues the raiders with divine guidance, and recovers everyone along with much spoil. The chapter ends with David sharing the recovered goods widely, showing both courage and generosity.", "As the Philistines assemble for war, their lords distrust David and insist that he not march with them. Achish defends David''s loyalty, but the commanders fear he will turn against them in battle, so David is sent home from Aphek. The chapter frees David from an impossible battlefield alliance before the final crisis with Saul unfolds.", "The Philistines defeat Israel at Mount Gilboa, and Saul''s sons fall beside him. Wounded and unable to continue, Saul falls on his own sword after his armor bearer refuses to kill him, and the Philistines later display the bodies in shame. Men of Jabesh-gilead recover the remains and bury them with fasting, ending Saul''s reign in grief and honor.", "Samuel hears the LORD calling in the night, and after Eli''s help he learns to answer, \"Speak, for your servant hears.\" The message confirms judgment on Eli''s house and cannot be hidden. Samuel grows into a trustworthy prophet whose words are established throughout Israel."]'::jsonb,
  'While David and his men are away, Amalekites raid Ziklag, burn the city, and take the families captive. David strengthens himself in the LORD, pursues the raiders with divine guidance, and recovers everyone along with much spoil. The chapter ends with David sharing the recovered goods widely, showing both courage and generosity.',
  'This advanced summary best matches 1 Samuel 30 (1 Samuel 30:1-8-1 Samuel 30:1-31).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 30
    AND difficulty_stage = 5
    AND prompt = 'Which advanced summary best matches 1 Samuel 30?'
);

