INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  31,
  5,
  'What final perspective best fits 1 Samuel 31?',
  '["The Philistines defeat Israel at Mount Gilboa, and Saul''s sons fall beside him. Wounded and unable to continue, Saul falls on his own sword after his armor bearer refuses to kill him, and the Philistines later display the bodies in shame. Men of Jabesh-gilead recover the remains and bury them with fasting, ending Saul''s reign in grief and honor.", "Hannah pours out her grief before the LORD at Shiloh and vows that if God gives her a son she will dedicate him to lifelong service. Eli misreads her silent prayer at first, then blesses her, and the LORD opens her womb. Samuel is born, weaned, and brought to the sanctuary as a living answer to prayer.", "The Philistines place the ark in Dagon''s temple, but Dagon falls before it and the people are struck with affliction. Town after town suffers because the ark brings the LORD''s presence into enemy territory. The chapter makes clear that the captured ark is not captive at all; it is still ruling.", "The Philistines send the ark back on a new cart with guilt offerings, testing whether the plague came from God or chance. The cows head straight for Beth-shemesh, confirming that the LORD is guiding the return. Israel rejoices but also learns reverence when some men look into the ark and are struck down."]'::jsonb,
  'The Philistines defeat Israel at Mount Gilboa, and Saul''s sons fall beside him. Wounded and unable to continue, Saul falls on his own sword after his armor bearer refuses to kill him, and the Philistines later display the bodies in shame. Men of Jabesh-gilead recover the remains and bury them with fasting, ending Saul''s reign in grief and honor.',
  'This final perspective fits 1 Samuel 31 (1 Samuel 31:1-6-1 Samuel 31:7-13).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 31
    AND difficulty_stage = 5
    AND prompt = 'What final perspective best fits 1 Samuel 31?'
);

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  9,
  31,
  5,
  'Which advanced summary best matches 1 Samuel 31?',
  '["The Philistines defeat Israel at Mount Gilboa, and Saul''s sons fall beside him. Wounded and unable to continue, Saul falls on his own sword after his armor bearer refuses to kill him, and the Philistines later display the bodies in shame. Men of Jabesh-gilead recover the remains and bury them with fasting, ending Saul''s reign in grief and honor.", "While David and his men are away, Amalekites raid Ziklag, burn the city, and take the families captive. David strengthens himself in the LORD, pursues the raiders with divine guidance, and recovers everyone along with much spoil. The chapter ends with David sharing the recovered goods widely, showing both courage and generosity.", "Hannah pours out her grief before the LORD at Shiloh and vows that if God gives her a son she will dedicate him to lifelong service. Eli misreads her silent prayer at first, then blesses her, and the LORD opens her womb. Samuel is born, weaned, and brought to the sanctuary as a living answer to prayer.", "Israel treats the ark like a talisman and marches it into battle, but the Philistines rout the army and capture the ark. Eli falls backward and dies when he hears the news, and his daughter-in-law names her son Ichabod because the glory has departed from Israel. The chapter is a stark warning that sacred objects cannot replace covenant faithfulness."]'::jsonb,
  'The Philistines defeat Israel at Mount Gilboa, and Saul''s sons fall beside him. Wounded and unable to continue, Saul falls on his own sword after his armor bearer refuses to kill him, and the Philistines later display the bodies in shame. Men of Jabesh-gilead recover the remains and bury them with fasting, ending Saul''s reign in grief and honor.',
  'This advanced summary best matches 1 Samuel 31 (1 Samuel 31:1-6-1 Samuel 31:7-13).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 9
    AND chapter = 31
    AND difficulty_stage = 5
    AND prompt = 'Which advanced summary best matches 1 Samuel 31?'
);

